import React, { useState } from 'react';
import { HeroSection } from './components/HeroSection';
import { ResultCard } from './components/ResultCard';
import { fetchCaseSummary } from './services/geminiService';
import { CaseSummary, SearchMode, Jurisdiction } from './types';

function App() {
  const [query, setQuery] = useState('');
  const [mode, setMode] = useState<SearchMode>(SearchMode.CASE_NAME);
  const [jurisdiction, setJurisdiction] = useState<Jurisdiction>(Jurisdiction.INDIA);
  const [summary, setSummary] = useState<CaseSummary | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = async () => {
    if (!query.trim()) return;

    setIsLoading(true);
    setError(null);
    setSummary(null);

    try {
      const isRawText = mode === SearchMode.TEXT_ANALYSIS;
      const result = await fetchCaseSummary(query, jurisdiction, isRawText);
      setSummary(result);
    } catch (err) {
      console.error(err);
      setError("Failed to generate summary. Please check your API Key, network connection, or try a clearer query.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen font-sans bg-[#f3f4f6]">

      {/* Navigation / Header */}
      <nav className="bg-slate-900 border-b border-slate-800 px-6 py-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2 text-white font-display text-xl font-bold">
            <svg className="w-8 h-8 text-legal-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 6l3 1m0 0l-3 9a5.002 5.002 0 006.001 0M6 7l3 9M6 7l6-2m6 2l3-1m-3 1l-3 9a5.002 5.002 0 006.001 0M18 7l3 9m-3-9l-6-2m0-2v2m0 16V5m0 16H9m3 0h3"></path></svg>
            JurisLens
          </div>
          <div className="hidden md:flex gap-6 text-sm text-slate-300">
            <a href="#" className="hover:text-white transition">Databases</a>
            <a href="#" className="hover:text-white transition">About</a>
            <a href="#" className="hover:text-white transition">GitHub</a>
          </div>
        </div>
      </nav>

      <HeroSection 
        query={query}
        setQuery={setQuery}
        mode={mode}
        setMode={setMode}
        jurisdiction={jurisdiction}
        setJurisdiction={setJurisdiction}
        onSearch={handleSearch}
        isLoading={isLoading}
      />

      {error && (
        <div className="max-w-2xl mx-auto mt-8 p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg text-center shadow-sm">
          <p className="font-semibold">Error Encountered</p>
          <p className="text-sm">{error}</p>
        </div>
      )}

      {!isLoading && !summary && !error && (
        <div className="max-w-4xl mx-auto mt-12 px-6 text-center">
          <h3 className="text-slate-400 font-serif italic text-lg mb-8">Featured Leading Cases</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 opacity-60 hover:opacity-100 transition-opacity">
            <button 
              onClick={() => { setQuery("Kesavananda Bharati v. State of Kerala"); setMode(SearchMode.CASE_NAME); }}
              className="p-4 bg-white rounded shadow-sm border border-slate-200 hover:border-legal-400 text-left"
            >
              <div className="font-bold text-slate-800 text-sm">Kesavananda Bharati</div>
              <div className="text-xs text-slate-500 mt-1">Basic Structure Doctrine</div>
            </button>
            <button 
              onClick={() => { setQuery("Maneka Gandhi v. Union of India"); setMode(SearchMode.CASE_NAME); }}
              className="p-4 bg-white rounded shadow-sm border border-slate-200 hover:border-legal-400 text-left"
            >
              <div className="font-bold text-slate-800 text-sm">Maneka Gandhi</div>
              <div className="text-xs text-slate-500 mt-1">Right to Personal Liberty</div>
            </button>
            <button 
              onClick={() => { setQuery("Vishaka v. State of Rajasthan"); setMode(SearchMode.CASE_NAME); }}
              className="p-4 bg-white rounded shadow-sm border border-slate-200 hover:border-legal-400 text-left"
            >
              <div className="font-bold text-slate-800 text-sm">Vishaka Guidelines</div>
              <div className="text-xs text-slate-500 mt-1">Sexual Harassment Laws</div>
            </button>
          </div>
        </div>
      )}

      {isLoading && (
        <div className="max-w-2xl mx-auto mt-12 text-center">
          <div className="inline-block animate-pulse">
            <div className="h-4 bg-slate-300 w-3/4 mx-auto rounded mb-3"></div>
            <div className="h-4 bg-slate-300 w-1/2 mx-auto rounded mb-3"></div>
            <div className="h-4 bg-slate-300 w-5/6 mx-auto rounded"></div>
          </div>
          <p className="text-slate-500 mt-4 font-serif italic">Analyzing precedents and extracting ratio decidendi...</p>
        </div>
      )}

      {summary && <ResultCard summary={summary} />}

      <footer className="bg-slate-900 text-slate-500 py-8 mt-auto border-t border-slate-800">
        <div className="max-w-6xl mx-auto px-6 text-center text-sm">
          <p className="mb-2">&copy; {new Date().getFullYear()} JurisLens Open Source.</p>
          <p className="text-xs">
            Disclaimer: AI-generated summaries are for educational research only and should not be cited as legal authority without verification from original judgment texts.
          </p>
        </div>
      </footer>
    </div>
  );
}

