import React, { useState } from 'react';
import { HeroSection } from './components/HeroSection';
import { ResultCard } from './components/ResultCard';
import { LoadingGavel } from './components/LoadingGavel';
import { CaseList } from './components/CaseList';
import { searchCaseDatabase, fetchCaseSummary } from './services/geminiService';
import { CaseSummary, CaseSearchResult, SearchMode, Jurisdiction } from './types';

function App() {
  const [query, setQuery] = useState('');
  const [mode, setMode] = useState<SearchMode>(SearchMode.CASE_NAME);
  const [jurisdiction, setJurisdiction] = useState<Jurisdiction>(Jurisdiction.INDIA);

  // State for Flow Management
  const [searchResults, setSearchResults] = useState<CaseSearchResult[] | null>(null);
  const [summary, setSummary] = useState<CaseSummary | null>(null);

  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<'SEARCHING' | 'SUMMARIZING' | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleInitialSearch = async () => {
    if (!query.trim()) return;

    setIsLoading(true);
    setLoadingStep('SEARCHING');
    setError(null);
    setSearchResults(null);
    setSummary(null);

    try {
      // If Text Analysis, skip directly to summary
      if (mode === SearchMode.TEXT_ANALYSIS) {
        setLoadingStep('SUMMARIZING');
        const result = await fetchCaseSummary(query, jurisdiction, true);
        setSummary(result);
      } else {
        // Step 1: Search for matches
        const matches = await searchCaseDatabase(query, jurisdiction);
        setSearchResults(matches);
      }
    } catch (err) {
      console.error(err);
      setError("The archives yielded no results. Please verify your query or citation.");
    } finally {
      if (mode !== SearchMode.TEXT_ANALYSIS) {
        setIsLoading(false);
        setLoadingStep(null);
      }
    }
  };

  const handleCaseSelect = async (selectedCase: CaseSearchResult) => {
    setIsLoading(true);
    setLoadingStep('SUMMARIZING');
    setSearchResults(null); // Clear list
    setError(null);

    try {
      // Step 2: Generate deep summary for selected case
      const fullQuery = `${selectedCase.caseName} ${selectedCase.citation}`;
      const result = await fetchCaseSummary(fullQuery, jurisdiction, false);
      setSummary(result);
    } catch (err) {
      console.error(err);
      setError("Unable to retrieve the full case roll. The document may be sealed or unavailable.");
    } finally {
      setIsLoading(false);
      setLoadingStep(null);
    }
  };

  // Reset functionality
  const resetSearch = () => {
    setSearchResults(null);
    setSummary(null);
    setQuery('');
  };

  return (
    <div className="min-h-screen text-slate-200 selection:bg-gold-500 selection:text-navy-900">

      {/* Navigation / Header - Glassmorphism */}
      <nav className="fixed w-full z-50 bg-navy-950/80 backdrop-blur-md border-b border-white/10">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={resetSearch}>
             <div className="w-8 h-8 bg-gradient-to-tr from-gold-600 to-gold-400 rounded-sm flex items-center justify-center shadow-lg">
                <span className="font-display font-bold text-navy-900 text-lg">J</span>
             </div>
             <span className="font-cinzel text-lg font-bold tracking-widest text-parchment-50">JURIS<span className="text-gold-500">LENS</span></span>
          </div>
          <div className="hidden md:flex gap-8 text-[10px] font-cinzel font-bold tracking-widest text-slate-400">
            <a href="#" className="hover:text-gold-400 transition-colors">GLOBAL SEARCH</a>
            <a href="#" className="hover:text-gold-400 transition-colors">ARCHIVES</a>
            <a href="#" className="hover:text-gold-400 transition-colors">ABOUT</a>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="relative min-h-screen">

        {/* Only show Hero Search if we don't have results yet */}
        {!summary && !searchResults && !isLoading && (
          <HeroSection 
            query={query}
            setQuery={setQuery}
            mode={mode}
            setMode={setMode}
            jurisdiction={jurisdiction}
            setJurisdiction={setJurisdiction}
            onSearch={handleInitialSearch}
            isLoading={isLoading}
          />
        )}

        {error && (
          <div className="max-w-2xl mx-auto mt-24 p-6 bg-crimson-900/20 border border-crimson-800 text-crimson-200 rounded text-center backdrop-blur-sm animate-fade-in-down">
            <p className="font-cinzel font-bold mb-2">ACCESS DENIED</p>
            <p className="font-serif italic text-sm">{error}</p>
            <button onClick={() => setError(null)} className="mt-4 text-xs font-bold underline">TRY AGAIN</button>
          </div>
        )}

        {/* Loading State with Gavel */}
        {isLoading && (
          <div className="pt-32">
            <LoadingGavel />
          </div>
        )}

        {/* Intermediate Search Results (Manupatra style list) */}
        {!isLoading && searchResults && (
           <div className="pt-32 animate-fade-in-up">
             <CaseList results={searchResults} onSelect={handleCaseSelect} />
           </div>
        )}

        {/* Final Summary Card */}
        {summary && (
          <div className="pt-24 animate-fade-in-up">
             <div className="max-w-5xl mx-auto px-4 mb-4">
                <button onClick={resetSearch} className="flex items-center gap-2 text-gold-600 text-xs font-cinzel font-bold tracking-widest hover:text-gold-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
                  NEW SEARCH
                </button>
             </div>
             <ResultCard summary={summary} />
          </div>
        )}

        {/* Empty State / Suggestions (Only on Home) */}
        {!isLoading && !summary && !searchResults && !error && (
          <div className="max-w-6xl mx-auto px-6 pb-20">
            <div className="flex items-center gap-4 mb-8">
               <div className="h-px bg-slate-800 flex-grow"></div>
               <span className="font-cinzel text-slate-600 text-xs tracking-[0.3em]">NOTABLE JUDGMENTS</span>
               <div className="h-px bg-slate-800 flex-grow"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <button 
                onClick={() => { setQuery("Kesavananda Bharati v. State of Kerala"); setMode(SearchMode.CASE_NAME); }}
                className="group relative p-6 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
              >
                <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <div className="font-display text-xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Kesavananda Bharati</div>
                <div className="font-serif text-sm text-slate-500 italic">"Basic Structure Doctrine"</div>
                <div className="mt-4 text-xs font-cinzel text-slate-600 tracking-wider">AIR 1973 SC 1461</div>
              </button>

              <button 
                onClick={() => { setQuery("Maneka Gandhi v. Union of India"); setMode(SearchMode.CASE_NAME); }}
                className="group relative p-6 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
              >
                <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <div className="font-display text-xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Maneka Gandhi</div>
                <div className="font-serif text-sm text-slate-500 italic">"Personal Liberty Expanded"</div>
                <div className="mt-4 text-xs font-cinzel text-slate-600 tracking-wider">1978 AIR 597</div>
              </button>

              <button 
                onClick={() => { setQuery("Right to Privacy Case"); setMode(SearchMode.CASE_NAME); }}
                className="group relative p-6 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
              >
                <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <div className="font-display text-xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Puttaswamy v. UOI</div>
                <div className="font-serif text-sm text-slate-500 italic">"Privacy as Fundamental Right"</div>
                <div className="mt-4 text-xs font-cinzel text-slate-600 tracking-wider">2017 10 SCC 1</div>
              </button>
            </div>
          </div>
        )}

      </main>

      {/* Footer */}
      {!searchResults && !summary && !isLoading && (
        <footer className="bg-navy-950 text-slate-600 py-12 border-t border-slate-900">
          <div className="max-w-6xl mx-auto px-6 flex flex-col items-center text-center">
            <div className="w-8 h-8 bg-slate-800 rounded-full flex items-center justify-center mb-6 text-slate-500">
              <span className="font-serif font-bold italic">§</span>
            </div>
            <p className="font-cinzel text-xs tracking-[0.2em] mb-4 text-slate-500">JURISLENS OPEN SOURCE INITIATIVE</p>
            <p className="text-xs font-serif italic max-w-lg mx-auto opacity-50">
              "Law is a reason free from passion." — Aristotle <br/>
              Automated summaries provided for educational research. Verify with original case rolls.
            </p>
          </div>
        </footer>
      )}
    </div>
  );
}

export default App;

export enum SearchMode {
  CITATION = 'CITATION',
  CASE_NAME = 'CASE_NAME',
  TEXT_ANALYSIS = 'TEXT_ANALYSIS'
}

export enum Jurisdiction {
  INDIA = 'India',
  USA = 'USA',
  UK = 'UK',
  AUSTRALIA = 'Australia',
  INTERNATIONAL = 'International'
}

export interface CaseSearchResult {
  caseName: string;
  citation: string;
  context: string; // A brief explanation of why this case matches the search
}

export interface RelatedCase {
  caseName: string;
  citation?: string;
  type: 'OVERRULED' | 'UPHELD' | 'DISTINGUISHED' | 'CITED' | 'RELIED_UPON';
  year?: number;
}

export interface CaseSummary {
  caseName: string;
  citation: string;
  court: string;
  year: number;
  benchStrength: string;
  judges: string[];
  jurisdiction: string;

  // Structured Headnote
  facts: string;
  issues: string[];
  petitionerArguments: string;
  respondentArguments: string;

  // The Core Judgment
  decision: string; // Held
  ratioDecidendi: string; // The principle of law
  obiterDicta?: string; // Incidental remarks

  significance: string; // Impact on law
  lawsInvolved: string[]; // Acts/Sections

  // Lineage
  precedents: RelatedCase[]; // Cases this case relies on
  subsequentDevelopments: RelatedCase[]; // Newer cases that cite this one
}

export interface SearchState {
  query: string;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
  rawText?: string;
}

export interface HistoryItem {
  query: string;
  timestamp: number;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
}

