import React, { useState, useEffect } from 'react';
import { HeroSection } from './components/HeroSection';
import { ResultCard } from './components/ResultCard';
import { LoadingGavel } from './components/LoadingGavel';
import { CaseList } from './components/CaseList';
import { searchCaseDatabase, fetchCaseSummary } from './services/geminiService';
import { CaseSummary, CaseSearchResult, SearchMode, Jurisdiction, HistoryItem } from './types';

function App() {
  const [query, setQuery] = useState('');
  const [mode, setMode] = useState<SearchMode>(SearchMode.CASE_NAME);
  const [jurisdiction, setJurisdiction] = useState<Jurisdiction>(Jurisdiction.INDIA);

  // State for Flow Management
  const [searchResults, setSearchResults] = useState<CaseSearchResult[] | null>(null);
  const [summary, setSummary] = useState<CaseSummary | null>(null);
  const [searchHistory, setSearchHistory] = useState<HistoryItem[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<'SEARCHING' | 'SUMMARIZING' | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('jurisLensHistory');
    if (saved) {
      setSearchHistory(JSON.parse(saved));
    }
  }, []);

  const addToHistory = (q: string, m: SearchMode, j: Jurisdiction) => {
    const newItem: HistoryItem = { query: q, timestamp: Date.now(), mode: m, jurisdiction: j };
    const updated = [newItem, ...searchHistory.filter(item => item.query !== q)].slice(0, 6);
    setSearchHistory(updated);
    localStorage.setItem('jurisLensHistory', JSON.stringify(updated));
  };

  const clearHistory = () => {
    setSearchHistory([]);
    localStorage.removeItem('jurisLensHistory');
  };

  const handleInitialSearch = async (overrideQuery?: string) => {
    const searchQuery = overrideQuery || query;
    if (!searchQuery.trim()) return;

    setIsLoading(true);
    setLoadingStep('SEARCHING');
    setError(null);
    setSearchResults(null);
    setSummary(null);

    // If searching via history click or related case, update the input box
    if (overrideQuery) setQuery(overrideQuery);

    try {
      if (mode === SearchMode.TEXT_ANALYSIS) {
        setLoadingStep('SUMMARIZING');
        const result = await fetchCaseSummary(searchQuery, jurisdiction, true);
        setSummary(result);
      } else {
        const matches = await searchCaseDatabase(searchQuery, jurisdiction);
        setSearchResults(matches);
      }
      addToHistory(searchQuery, mode, jurisdiction);
    } catch (err) {
      console.error(err);
      setError("The archives yielded no results. Please verify your query or citation.");
    } finally {
      if (mode !== SearchMode.TEXT_ANALYSIS) {
        setIsLoading(false);
        setLoadingStep(null);
      }
    }
  };

  const handleCaseSelect = async (selectedCase: CaseSearchResult) => {
    setIsLoading(true);
    setLoadingStep('SUMMARIZING');
    setSearchResults(null);
    setError(null);

    try {
      const fullQuery = `${selectedCase.caseName} ${selectedCase.citation}`;
      const result = await fetchCaseSummary(fullQuery, jurisdiction, false);
      setSummary(result);
    } catch (err) {
      console.error(err);
      setError("Unable to retrieve the full case roll. The document may be sealed or unavailable.");
    } finally {
      setIsLoading(false);
      setLoadingStep(null);
    }
  };

  const resetSearch = () => {
    setSearchResults(null);
    setSummary(null);
    setQuery('');
  };

  // Helper to trigger search from history
  const handleHistoryClick = (item: HistoryItem) => {
    setMode(item.mode);
    setJurisdiction(item.jurisdiction);
    handleInitialSearch(item.query);
  };

  return (
    <div className="min-h-screen text-slate-200 selection:bg-gold-500 selection:text-navy-900 font-sans">

      {/* Navigation / Header - Glassmorphism */}
      <nav className="fixed w-full z-50 bg-navy-950/90 backdrop-blur-xl border-b border-white/5 shadow-2xl">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={resetSearch}>
             {/* Nav Logo SVG */}
             <div className="w-10 h-10 relative">
               <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-lg group-hover:rotate-12 transition-transform">
                 <path d="M45 20 V 65 Q 45 85 25 85" fill="none" stroke="#fbbf24" strokeWidth="10" strokeLinecap="round" />
                 <path d="M20 30 Q 80 10 90 40 T 50 80 T 10 50" fill="none" stroke="#d97706" strokeWidth="4" strokeLinecap="round" />
                 <rect x="30" y="15" width="30" height="12" rx="2" fill="#fbbf24" transform="rotate(-10 45 20)" />
               </svg>
             </div>
             <span className="font-cinzel text-xl font-bold tracking-widest text-parchment-50 group-hover:text-gold-400 transition-colors">JURIS<span className="text-shine">LENS</span></span>
          </div>
          <div className="hidden md:flex gap-8 text-[10px] font-cinzel font-bold tracking-widest text-slate-400">
            <a href="#" className="hover:text-gold-400 transition-colors">GLOBAL SEARCH</a>
            <a href="#" className="hover:text-gold-400 transition-colors">ARCHIVES</a>
            <a href="#" className="hover:text-gold-400 transition-colors">ABOUT</a>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="relative min-h-screen">

        {/* Only show Hero Search if we don't have results yet */}
        {!summary && !searchResults && !isLoading && (
          <HeroSection 
            query={query}
            setQuery={setQuery}
            mode={mode}
            setMode={setMode}
            jurisdiction={jurisdiction}
            setJurisdiction={setJurisdiction}
            onSearch={() => handleInitialSearch()}
            isLoading={isLoading}
          />
        )}

        {error && (
          <div className="max-w-2xl mx-auto mt-24 p-6 bg-crimson-900/20 border border-crimson-800 text-crimson-200 rounded text-center backdrop-blur-sm animate-fade-in-down">
            <p className="font-cinzel font-bold mb-2">ACCESS DENIED</p>
            <p className="font-serif italic text-sm">{error}</p>
            <button onClick={() => setError(null)} className="mt-4 text-xs font-bold underline">TRY AGAIN</button>
          </div>
        )}

        {/* Loading State with Gavel */}
        {isLoading && (
          <div className="pt-20">
            <LoadingGavel />
          </div>
        )}

        {/* Intermediate Search Results */}
        {!isLoading && searchResults && (
           <div className="pt-32 animate-fade-in-up">
             <CaseList results={searchResults} onSelect={handleCaseSelect} />
           </div>
        )}

        {/* Final Summary Card */}
        {summary && (
          <div className="pt-24 animate-fade-in-up">
             <div className="max-w-6xl mx-auto px-4 mb-4">
                <button onClick={resetSearch} className="flex items-center gap-2 text-gold-600 text-xs font-cinzel font-bold tracking-widest hover:text-gold-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
                  NEW SEARCH
                </button>
             </div>
             <ResultCard 
               summary={summary} 
               onRelatedCaseClick={(name) => {
                 setQuery(name);
                 setMode(SearchMode.CASE_NAME);
                 handleInitialSearch(name);
                 window.scrollTo({ top: 0, behavior: 'smooth' });
               }}
             />
          </div>
        )}

        {/* Search History (Replaces Notable Judgments when history exists) */}
        {!isLoading && !summary && !searchResults && !error && (
          <div className="max-w-6xl mx-auto px-6 pb-20">
            <div className="flex items-center gap-4 mb-8">
               <div className="h-px bg-slate-800 flex-grow"></div>
               <span className="font-cinzel text-slate-600 text-xs tracking-[0.3em]">
                 {searchHistory.length > 0 ? "RECENT INQUIRIES" : "NOTABLE PRECEDENTS"}
               </span>
               <div className="h-px bg-slate-800 flex-grow"></div>
               {searchHistory.length > 0 && (
                 <button onClick={clearHistory} className="text-[10px] text-slate-600 hover:text-crimson-500 font-cinzel font-bold">
                   CLEAR HISTORY
                 </button>
               )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {searchHistory.length > 0 ? (
                searchHistory.map((item, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleHistoryClick(item)}
                    className="group relative p-8 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm hover:shadow-2xl hover:-translate-y-1"
                  >
                    <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <div className="flex justify-between items-start mb-4">
                      <span className="text-[10px] font-cinzel font-bold text-slate-500 bg-navy-950 px-2 py-1">{item.jurisdiction}</span>
                      <span className="text-[10px] font-mono text-slate-600">{new Date(item.timestamp).toLocaleDateString()}</span>
                    </div>
                    <div className="font-display text-xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors line-clamp-2">
                      {item.query}
                    </div>
                    <div className="text-xs font-serif text-slate-500 italic">Re-open case file &rarr;</div>
                  </button>
                ))
              ) : (
                /* Default Suggestions if History is Empty */
                <>
                  <button 
                    onClick={() => handleInitialSearch("Kesavananda Bharati v. State of Kerala")}
                    className="group relative p-8 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
                  >
                    <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <div className="font-display text-2xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Kesavananda Bharati</div>
                    <div className="font-serif text-sm text-slate-500 italic">"Basic Structure Doctrine"</div>
                    <div className="mt-6 text-xs font-cinzel text-slate-600 tracking-wider">AIR 1973 SC 1461</div>
                  </button>

                  <button 
                    onClick={() => handleInitialSearch("Maneka Gandhi v. Union of India")}
                    className="group relative p-8 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
                  >
                    <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <div className="font-display text-2xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Maneka Gandhi</div>
                    <div className="font-serif text-sm text-slate-500 italic">"Personal Liberty Expanded"</div>
                    <div className="mt-6 text-xs font-cinzel text-slate-600 tracking-wider">1978 AIR 597</div>
                  </button>

                  <button 
                    onClick={() => handleInitialSearch("Puttaswamy v. Union of India")}
                    className="group relative p-8 bg-navy-900/50 border border-slate-800 hover:border-gold-600/50 transition-all duration-300 text-left overflow-hidden rounded-sm"
                  >
                    <div className="absolute inset-0 bg-gold-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <div className="font-display text-2xl text-parchment-100 mb-2 group-hover:text-gold-400 transition-colors">Puttaswamy v. UOI</div>
                    <div className="font-serif text-sm text-slate-500 italic">"Privacy as Fundamental Right"</div>
                    <div className="mt-6 text-xs font-cinzel text-slate-600 tracking-wider">2017 10 SCC 1</div>
                  </button>
                </>
              )}
            </div>
          </div>
        )}

      </main>

      {/* Footer */}
      {!searchResults && !summary && !isLoading && (
        <footer className="bg-navy-950 text-slate-600 py-12 border-t border-slate-900">
          <div className="max-w-6xl mx-auto px-6 flex flex-col items-center text-center">
            <div className="w-10 h-10 bg-slate-900 rounded-full flex items-center justify-center mb-6 text-slate-500 shadow-inner">
              <span className="font-serif font-bold italic text-lg">§</span>
