export enum SearchMode {
  CITATION = 'CITATION',
  CASE_NAME = 'CASE_NAME',
  TEXT_ANALYSIS = 'TEXT_ANALYSIS'
}

export enum Jurisdiction {
  INDIA = 'India',
  USA = 'USA',
  UK = 'UK',
  AUSTRALIA = 'Australia',
  INTERNATIONAL = 'International'
}

export interface CaseSearchResult {
  caseName: string;
  citation: string;
  context: string; // A brief explanation of why this case matches the search
}

export interface RelatedCase {
  caseName: string;
  citation?: string;
  type: 'OVERRULED' | 'UPHELD' | 'DISTINGUISHED' | 'CITED' | 'RELIED_UPON';
  year?: number;
}

export interface TimelineEvent {
  date: string;
  event: string;
}

export interface CaseSummary {
  caseName: string;
  citation: string;
  court: string;
  year: number;
  benchStrength: string;
  judges: string[];
  jurisdiction: string;

  // Structured Headnote
  facts: string;
  timeline: TimelineEvent[]; // "If this happened..." chronology
  issues: string[];
  petitionerArguments: string;
  respondentArguments: string;

  // The Core Judgment
  decision: string; // Held
  ratioDecidendi: string; // The principle of law
  obiterDicta?: string; // Incidental remarks

  significance: string; // Impact on law
  lawsInvolved: string[]; // Acts/Sections

  // Lineage
  precedents: RelatedCase[]; // Cases this case relies on
  subsequentDevelopments: RelatedCase[]; // Newer cases that cite this one
}

export interface SearchState {
  query: string;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
  rawText?: string;
}

export interface HistoryItem {
  query: string;
  timestamp: number;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Schema definition for the structured legal output
const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation (e.g., AIR 1973 SC 1461)" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges or bench type (e.g., Constitution Bench)" },
    judges: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of judges on the bench"
    },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Brief summary of the material facts (max 150 words)" },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "Date or Year (e.g., '1970' or '24th April 1973')" },
          event: { type: Type.STRING, description: "What happened (e.g., 'Petition filed in High Court')" }
        }
      },
      description: "Chronological sequence of events leading to the judgment. 'If this happened, then that happened'."
    },
    issues: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of legal issues or questions of law raised"
    },
    petitionerArguments: { type: Type.STRING, description: "Core arguments by the petitioner/appellant" },
    respondentArguments: { type: Type.STRING, description: "Core arguments by the respondent" },
    decision: { type: Type.STRING, description: "The final verdict/holding of the court" },
    ratioDecidendi: { type: Type.STRING, description: "The core legal principle derived (Ratio)" },
    obiterDicta: { type: Type.STRING, description: "Any significant incidental remarks (Obiter)" },
    significance: { type: Type.STRING, description: "Impact on the legal landscape or future precedents" },
    lawsInvolved: {
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of Specific Acts, Articles, or Sections referenced (e.g. 'Article 21', 'Section 302 IPC')"
    },
    precedents: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['RELIED_UPON', 'DISTINGUISHED', 'OVERRULED'] }
        }
      },
      description: "Older cases that this judgment relied upon or discussed"
    },
    subsequentDevelopments: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['OVERRULED', 'UPHELD', 'CITED'] },
          year: { type: Type.INTEGER }
        }
      },
      description: "Important newer cases that cite, overrule, or uphold this case"
    }
  },
  required: ["caseName", "citation", "court", "year", "facts", "timeline", "issues", "decision", "ratioDecidendi", "significance"]
};

const searchResultSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      caseName: { type: Type.STRING },
      citation: { type: Type.STRING },
      context: { type: Type.STRING, description: "1 sentence explaining why this matches the query" }
    },
    required: ["caseName", "citation", "context"]
  }
};

// Step 1: Search and Disambiguate
export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    const prompt = `
      You are an expert Legal Search Engine (like Manupatra/SCC Online).
      The user is searching for: "${query}" in the jurisdiction of ${jurisdiction}.

      The user might have provided a case name, a citation, or a story/description of the facts.
      Identify the top 3-4 most likely legal cases that match this query.

      Return a JSON array of case options.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
        temperature: 0.3,
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSearchResult[];
  } catch (error) {
    console.error("Search Error:", error);
    throw error;
  }
};

// Step 2: Detailed Summary
export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";

    if (isRawText) {
      prompt = `
        You are an expert Legal Researcher and Summarizer. 
        Analyze the following raw judgment text provided below. 
        Extract the key legal elements and structure them into a comprehensive legal headnote.

        CRITICAL: 
        1. Create a chronological 'timeline' of events ("If this happened, then that happened").
        2. Identify specific Laws/Articles involved.

        Raw Text:
        """
        ${query.substring(0, 30000)} 
        """
        (Text truncated if too long)
      `;
    } else {
      prompt = `
        You are an expert Legal Researcher. 
        The user wants a detailed summary of the specific legal case: "${query}" (${jurisdiction}).

        Provide a structured summary similar to SCC Online or Manupatra headnotes.
        Ensure the "Ratio Decidendi" is legally precise and distinguished from Obiter.

        CRITICAL REQUIREMENTS:
        1. 'timeline': Create a step-by-step chronology of events leading to this judgment.
        2. 'lawsInvolved': List specific Articles (e.g., Art 14, 21) or Sections (e.g., IPC 302).
        3. 'precedents' & 'subsequentDevelopments': List important related cases.

        Use formal legal language but make it accessible.
      `;
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
        temperature: 0.2, 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSummary;

  } catch (error) {
    console.error("Gemini Legal Search Error:", error);
    throw error;
  }
};

