import React, { useState, useEffect } from 'react';
import { HeroSection } from './components/HeroSection';
import { ResultCard } from './components/ResultCard';
import { LoadingGavel } from './components/LoadingGavel';
import { CaseList } from './components/CaseList';
import { searchCaseDatabase, fetchCaseSummary } from './services/geminiService';
import { CaseSummary, CaseSearchResult, SearchMode, Jurisdiction, HistoryItem } from './types';

function App() {
  const [query, setQuery] = useState('');
  const [mode, setMode] = useState<SearchMode>(SearchMode.CASE_NAME);
  const [jurisdiction, setJurisdiction] = useState<Jurisdiction>(Jurisdiction.INDIA);

  // Vakil Mode State
  const [isVakilMode, setIsVakilMode] = useState(false);

  // State for Flow Management
  const [searchResults, setSearchResults] = useState<CaseSearchResult[] | null>(null);
  const [summary, setSummary] = useState<CaseSummary | null>(null);
  const [searchHistory, setSearchHistory] = useState<HistoryItem[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('jurisLensHistory');
    if (saved) {
      setSearchHistory(JSON.parse(saved));
    }
  }, []);

  const addToHistory = (q: string, m: SearchMode, j: Jurisdiction) => {
    const newItem: HistoryItem = { query: q, timestamp: Date.now(), mode: m, jurisdiction: j };
    const updated = [newItem, ...searchHistory.filter(item => item.query !== q)].slice(0, 6);
    setSearchHistory(updated);
    localStorage.setItem('jurisLensHistory', JSON.stringify(updated));
  };

  const clearHistory = () => {
    setSearchHistory([]);
    localStorage.removeItem('jurisLensHistory');
  };

  const handleInitialSearch = async (overrideQuery?: string) => {
    const searchQuery = overrideQuery || query;
    if (!searchQuery.trim()) return;

    setIsLoading(true);
    setError(null);
    setSearchResults(null);
    setSummary(null);

    if (overrideQuery) setQuery(overrideQuery);

    try {
      if (mode === SearchMode.TEXT_ANALYSIS) {
        const result = await fetchCaseSummary(searchQuery, jurisdiction, isVakilMode, true);
        setSummary(result);
      } else {
        const matches = await searchCaseDatabase(searchQuery, jurisdiction);
        setSearchResults(matches);
      }
      addToHistory(searchQuery, mode, jurisdiction);
    } catch (err) {
      console.error(err);
      setError("The archives yielded no results. Please verify your query or citation.");
    } finally {
      if (mode !== SearchMode.TEXT_ANALYSIS) {
        setIsLoading(false);
      }
    }
  };

  const handleCaseSelect = async (selectedCase: CaseSearchResult) => {
    setIsLoading(true);
    setSearchResults(null);
    setError(null);

    try {
      const fullQuery = `${selectedCase.caseName} ${selectedCase.citation}`;
      const result = await fetchCaseSummary(fullQuery, jurisdiction, isVakilMode, false);
      setSummary(result);
    } catch (err) {
      console.error(err);
      setError("Unable to retrieve the full case roll.");
    } finally {
      setIsLoading(false);
    }
  };

  const resetSearch = () => {
    setSearchResults(null);
    setSummary(null);
    setQuery('');
  };

  const handleHistoryClick = (item: HistoryItem) => {
    setMode(item.mode);
    setJurisdiction(item.jurisdiction);
    handleInitialSearch(item.query);
  };

  return (
    <div className={`min-h-screen font-sans transition-colors duration-500 ${isVakilMode ? 'bg-zinc-950 selection:bg-neon-green selection:text-black' : 'bg-slate-900 text-slate-200 selection:bg-gold-500 selection:text-navy-900'}`}>

      {/* Vakil Mode Toggle Button (Floating) */}
      <button 
        onClick={() => setIsVakilMode(!isVakilMode)}
        className={`fixed bottom-8 right-8 z-50 p-4 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 flex items-center justify-center border-2 ${isVakilMode ? 'bg-black border-neon-green shadow-[0_0_20px_#39ff14]' : 'bg-navy-900 border-gold-500 shadow-gold-500/20'}`}
        title="Toggle Vakil Mode (Street Smart)"
      >
         <span className="text-2xl">{isVakilMode ? '⚡' : '⚖️'}</span>
      </button>

      {/* Navigation */}
      <nav className="fixed w-full z-50 bg-navy-950/90 backdrop-blur-xl border-b border-white/5 shadow-2xl">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={resetSearch}>
             <div className="w-10 h-10 relative">
               <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-lg group-hover:rotate-12 transition-transform">
                 <path d="M45 20 V 65 Q 45 85 25 85" fill="none" stroke={isVakilMode ? "#39ff14" : "#fbbf24"} strokeWidth="10" strokeLinecap="round" />
                 <path d="M20 30 Q 80 10 90 40 T 50 80 T 10 50" fill="none" stroke={isVakilMode ? "#efff04" : "#d97706"} strokeWidth="4" strokeLinecap="round" />
               </svg>
             </div>
             <span className={`font-cinzel text-xl font-bold tracking-widest transition-colors ${isVakilMode ? 'text-neon-green' : 'text-parchment-50'}`}>JURIS<span className={isVakilMode ? 'text-neon-yellow' : 'text-shine'}>LENS</span></span>
          </div>
        </div>
      </nav>

      <main className="relative min-h-screen">

        {!summary && !searchResults && !isLoading && (
          <HeroSection 
            query={query}
            setQuery={setQuery}
            mode={mode}
            setMode={setMode}
            jurisdiction={jurisdiction}
            setJurisdiction={setJurisdiction}
            onSearch={() => handleInitialSearch()}
            isLoading={isLoading}
          />
        )}

        {isLoading && (
          <div className="pt-20">
            <LoadingGavel />
          </div>
        )}

        {!isLoading && searchResults && (
           <div className="pt-32 animate-fade-in-up">
             <CaseList results={searchResults} onSelect={handleCaseSelect} />
           </div>
        )}

        {summary && (
          <div className="pt-24 animate-fade-in-up">
             <div className="max-w-6xl mx-auto px-4 mb-4">
                <button onClick={resetSearch} className={`flex items-center gap-2 text-xs font-cinzel font-bold tracking-widest ${isVakilMode ? 'text-neon-green hover:text-white' : 'text-gold-600 hover:text-gold-400'}`}>
                  <span>&larr;</span> NEW SEARCH
                </button>
             </div>
             <ResultCard 
               summary={summary} 
               isVakilMode={isVakilMode}
               onRelatedCaseClick={(name) => {
                 setQuery(name);
                 setMode(SearchMode.CASE_NAME);
                 handleInitialSearch(name);
                 window.scrollTo({ top: 0, behavior: 'smooth' });
               }}
             />
          </div>
        )}

        {!isLoading && !summary && !searchResults && !error && (
          <div className="max-w-6xl mx-auto px-6 pb-20">
             {/* History UI reused here... */}
          </div>
        )}

      </main>
    </div>
  );
}

export default App;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Schema definition for the structured legal output
const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation (e.g., AIR 1973 SC 1461)" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges or bench type (e.g., Constitution Bench)" },
    judges: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of judges on the bench"
    },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Extensive and detailed narrative of the material facts. Aim for depth (approx 300-400 words)." },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "Date or Year" },
          event: { type: Type.STRING, description: "What happened" }
        }
      },
      description: "Chronological sequence of events."
    },
    irac: {
      type: Type.OBJECT,
      properties: {
        issue: { type: Type.STRING, description: "The specific legal question before the court (Exam style)." },
        rule: { type: Type.STRING, description: "The specific statutes or precedents applied (The Rule). Provide detailed citations." },
        analysis: { type: Type.STRING, description: "Comprehensive application of law to facts (The Analysis). This should be the longest section (approx 400 words)." },
        conclusion: { type: Type.STRING, description: "The final holding." }
      },
      description: "IRAC Analysis for law students."
    },
    vakilTake: {
      type: Type.STRING,
      description: "A street-smart, practical analysis of the case. What is the real-world implication? Are there loopholes? Write this in a sharp, professional yet savvy tone."
    },
    issues: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of legal issues or questions of law raised"
    },
    petitionerArguments: { type: Type.STRING, description: "Core arguments by the petitioner/appellant" },
    respondentArguments: { type: Type.STRING, description: "Core arguments by the respondent" },
    decision: { type: Type.STRING, description: "The final verdict/holding of the court" },
    ratioDecidendi: { type: Type.STRING, description: "The core legal principle derived (Ratio)" },
    obiterDicta: { type: Type.STRING, description: "Any significant incidental remarks (Obiter)" },
    significance: { type: Type.STRING, description: "Impact on the legal landscape or future precedents" },
    lawsInvolved: {
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of Specific Acts, Articles, or Sections referenced (e.g. 'Article 21', 'Section 302 IPC')"
    },
    precedents: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['RELIED_UPON', 'DISTINGUISHED', 'OVERRULED'] }
        }
      },
      description: "Older cases that this judgment relied upon or discussed"
    },
    subsequentDevelopments: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['OVERRULED', 'UPHELD', 'CITED'] },
          year: { type: Type.INTEGER }
        }
      },
      description: "Important newer cases that cite, overrule, or uphold this case. REQUIRED FIELD."
    }
  },
  required: ["caseName", "citation", "court", "year", "facts", "timeline", "irac", "issues", "decision", "ratioDecidendi", "significance", "subsequentDevelopments"]
};

const searchResultSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      caseName: { type: Type.STRING },
      citation: { type: Type.STRING },
      context: { type: Type.STRING, description: "1 sentence explaining why this matches the query" }
    },
    required: ["caseName", "citation", "context"]
  }
};

export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    const prompt = `
      You are an expert Legal Search Engine.
      The user is searching for: "${query}" in the jurisdiction of ${jurisdiction}.
      Identify the top 3-4 most likely legal cases that match this query.
      Return a JSON array of case options.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
        temperature: 0.3,
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSearchResult[];
  } catch (error) {
    console.error("Search Error:", error);
    throw error;
  }
};

export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";

    // The "Vakil" Persona Injection
    const persona = isVakilMode 
      ? `You are a legendary, street-smart Indian lawyer (Vakil) who knows the system inside out. 
         You don't just summarize; you analyze strategy, loopholes, and real-world impact.
         Your tone should be professional but sharp, authoritative, and practical. 
         Focus on the 'vakilTake' - tell me what really matters.`
      : `You are an expert Legal Researcher. Use formal, academic legal language.`;

    const lengthInstruction = `
      PROVIDE A DEEP DIVE ANALYSIS.
      The user wants a comprehensive understanding, equivalent to reading a 1000-word case brief.
      - Expand significantly on the 'facts'.
      - The 'irac.analysis' must be very detailed, covering specific judicial reasoning.
    `;

    if (isRawText) {
      prompt = `
        ${persona}
        ${lengthInstruction}
        Analyze the following raw judgment text provided below. 
        Extract the key legal elements and structure them into a comprehensive legal headnote.

        CRITICAL: 
        1. Create a chronological 'timeline'.
        2. Create an 'IRAC' analysis.
        3. Identify 'subsequentDevelopments' - cases that came AFTER this one and affected it.

        Raw Text:
        """
        ${query.substring(0, 30000)} 
        """
      `;
    } else {
      prompt = `
        ${persona}
        ${lengthInstruction}
        The user wants a detailed summary of the specific legal case: "${query}" (${jurisdiction}).

        Provide a structured summary.

        CRITICAL REQUIREMENTS:
        1. 'irac': IRAC analysis for exams. Detailed application of rule to facts.
        2. 'vakilTake': A practical, strategic analysis of the judgment (Strategy/Impact).
        3. 'subsequentDevelopments': MANDATORY. List major cases that overruled, followed, or distinguished this case.

        Ensure accuracy.
      `;
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
        temperature: 0.2, 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSummary;

  } catch (error) {
    console.error("Gemini Legal Search Error:", error);
    throw error;
  }
};

