          <h3 className={`${theme.fontHead} text-center text-lg mb-8 tracking-widest font-bold opacity-70`}>CASE LINEAGE & TRAJECTORY</h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            <div>
              <div className="flex items-center gap-3 mb-4 border-b pb-2 border-white/10">
                 <h4 className={`${theme.fontHead} text-xs font-bold tracking-widest opacity-60`}>PRECEDENTS</h4>
