import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Schema definition for the structured legal output
const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation (e.g., AIR 1973 SC 1461)" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges or bench type (e.g., Constitution Bench)" },
    judges: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of judges on the bench"
    },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Extensive and detailed narrative of the material facts. For Vakil Mode, provide near-verbatim detail from the judgment where possible. Target 500+ words." },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "Date or Year" },
          event: { type: Type.STRING, description: "What happened" }
        }
      },
      description: "Chronological sequence of events."
    },
    irac: {
      type: Type.OBJECT,
      properties: {
        issue: { type: Type.STRING, description: "The specific legal question before the court." },
        rule: { type: Type.STRING, description: "The specific statutes or precedents applied (The Rule). Provide detailed citations." },
        analysis: { type: Type.STRING, description: "Comprehensive application of law to facts. This section MUST be exhaustive. Discuss majority and dissenting opinions separately if applicable. Target 800-1000 words." },
        conclusion: { type: Type.STRING, description: "The final holding." }
      },
      description: "IRAC Analysis for law students."
    },
    vakilTake: {
      type: Type.STRING,
      description: "A street-smart, practical analysis. Identify loopholes, strategic brilliance, and procedural nuances. Why was this case REALLY won or lost?"
    },
    issues: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of legal issues or questions of law raised"
    },
    petitionerArguments: { type: Type.STRING, description: "Detailed arguments by the petitioner/appellant" },
    respondentArguments: { type: Type.STRING, description: "Detailed arguments by the respondent" },
    decision: { type: Type.STRING, description: "The final verdict/holding of the court" },
    ratioDecidendi: { type: Type.STRING, description: "The core legal principle derived (Ratio)" },
    obiterDicta: { type: Type.STRING, description: "Any significant incidental remarks (Obiter)" },
    significance: { type: Type.STRING, description: "Impact on the legal landscape or future precedents" },
    lawsInvolved: {
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of Specific Acts, Articles, or Sections referenced"
    },
    precedents: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['RELIED_UPON', 'DISTINGUISHED', 'OVERRULED'] }
        }
      },
      description: "Older cases that this judgment relied upon or discussed"
    },
    subsequentDevelopments: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['OVERRULED', 'UPHELD', 'CITED'] },
          year: { type: Type.INTEGER }
        }
      },
      description: "List strictly the major cases that have cited, overruled, or distinguished this case in later years."
    },
    fullTextUrl: { type: Type.STRING, description: "A valid URL to the full judgment PDF or text (e.g. from indiankanoon.org or sci.gov.in) if known." }
  },
  required: ["caseName", "citation", "court", "year", "facts", "timeline", "irac", "issues", "decision", "ratioDecidendi", "significance", "subsequentDevelopments"]
};

const searchResultSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      caseName: { type: Type.STRING },
      citation: { type: Type.STRING },
      context: { type: Type.STRING, description: "Why this case matches the query" },
      pdfUrl: { type: Type.STRING, description: "Direct URL to PDF if available" }
    },
    required: ["caseName", "citation", "context"]
  }
};

export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    // Updated Prompt for Boolean and Issue Search
    const prompt = `
      You are an expert Legal Search Engine.
      The user is searching for: "${query}" in the jurisdiction of ${jurisdiction}.

      SEARCH LOGIC:
      1. Interpret Boolean operators (AND, OR, NOT) if present in the query.
      2. If the query is an "Issue" (e.g., "right to privacy", "triple talaq"), find leading cases on that subject.
      3. If the query is a Case Name or Citation, find exact matches.

      Identify the top 4 most relevant legal cases.
      For each case, try to provide a 'pdfUrl' if a standard stable link exists (like main.sci.gov.in or indiankanoon.org).

      Return a JSON array.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
        temperature: 0.3,
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSearchResult[];
  } catch (error) {
    console.error("Search Error:", error);
    throw error;
  }
};

export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";

    // The "Vakil" Persona Injection with Extreme Depth Instruction
    const persona = isVakilMode 
      ? `You are a legendary Senior Advocate (Vakil) in the Supreme Court.
         You provide EXTREMELY DETAILED, EXHAUSTIVE, AND STRATEGIC analyses.
         Your goal is to produce a summary equivalent to a 3000-word case commentary.

         TONE: Authoritative, cynical, highly detailed, bold.

         INSTRUCTIONS FOR 'VAKIL MODE':
         1. 'facts': Must be a long narrative (at least 600 words) covering every procedural step.
         2. 'irac.analysis': Must be exhaustive (at least 1000 words). Breakdown separate opinions of judges. Quote the judgment extensively.
         3. 'subsequentDevelopments': You MUST identify cases that came after this and changed the law.`
      : `You are an expert Legal Researcher. Use formal, academic legal language. Provide a comprehensive summary (approx 1000 words).`;

    if (isRawText) {
      prompt = `
        ${persona}
        Analyze the provided raw judgment text. 
        Extract key elements into the structured format.

        Raw Text:
        """
        ${query.substring(0, 30000)} 
        """
      `;
    } else {
      prompt = `
        ${persona}
        The user wants a detailed summary of: "${query}" (${jurisdiction}).

        Provide the output in the defined JSON schema.
        Ensure 'subsequentDevelopments' is populated with array of related cases.
        Ensure 'fullTextUrl' is provided if a likely URL exists.
      `;
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
        temperature: 0.2, 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSummary;

  } catch (error) {
    console.error("Gemini Legal Search Error:", error);
    throw error;
  }
};

