  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Autocomplete logic
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  // Click outside to close
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-32 pb-20 px-4 overflow-hidden min-h-[70vh] flex flex-col justify-center">

      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1200px] h-[800px] bg-navy-800/30 rounded-full blur-[150px] -z-10 pointer-events-none"></div>

      <div className="max-w-6xl mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-12 animate-fade-in-down flex flex-col items-center">

          <div className="relative w-28 h-28 mb-4 group cursor-default">
             <div className="absolute inset-0 bg-gold-500/10 blur-2xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
             <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl overflow-visible">
               <defs>
                 <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                   <stop offset="0%" stopColor="#b45309" />
                   <stop offset="50%" stopColor="#fbbf24" />
                   <stop offset="100%" stopColor="#b45309" />
                 </linearGradient>
               </defs>
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="url(#goldGrad)" strokeWidth="1" className="opacity-30" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fbbf24" strokeWidth="1" className="opacity-50" strokeDasharray="2 2" />
             </svg>
          </div>

          <div className="inline-flex items-center justify-center px-6 py-2 mb-6 border-y border-gold-600/30 bg-navy-950/40 backdrop-blur-md">
            <span className="text-gold-500 text-[10px] font-cinzel tracking-[0.4em] font-bold uppercase">
              Est. 2026 • AI Legal Research
            </span>
          </div>

          <h1 className="font-display text-7xl md:text-9xl font-bold mb-4 tracking-tighter text-parchment-50 drop-shadow-2xl relative inline-block">
            Juris<span className="text-shine italic font-serif font-light animate-shine">Lens</span>
          </h1>

          <div className="flex items-center justify-center gap-6 my-8 opacity-70">
            <div className="h-px w-24 bg-gradient-to-r from-transparent to-gold-600/50"></div>
            <p className="text-slate-300 text-xl font-serif italic tracking-wide">
              "Fiat Justitia Ruat Caelum"
            </p>
            <div className="h-px w-24 bg-gradient-to-l from-transparent to-gold-600/50"></div>
          </div>
        </div>

        {/* Search Interface */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-navy-950/80 backdrop-blur-2xl rounded shadow-[0_30px_100px_rgba(0,0,0,0.8)] border border-slate-700/80 p-4 max-w-5xl mx-auto transform transition-all hover:border-gold-600/40 group hover:shadow-[0_30px_100px_rgba(251,191,36,0.1)] relative z-50">
            <div className="flex flex-col md:flex-row gap-4">

              <div className="relative min-w-[200px] bg-navy-900 rounded border border-slate-800">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-5 bg-transparent text-slate-300 font-cinzel text-xs font-bold tracking-wider outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME / ISSUE</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gold-600">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
