export enum SearchMode {
  CITATION = 'CITATION',
  CASE_NAME = 'CASE_NAME',
  TEXT_ANALYSIS = 'TEXT_ANALYSIS'
}

export enum Jurisdiction {
  INDIA = 'India',
  USA = 'USA',
  UK = 'UK',
  AUSTRALIA = 'Australia',
  INTERNATIONAL = 'International'
}

export interface CaseSearchResult {
  caseName: string;
  citation: string;
  context: string; // A brief explanation of why this case matches the search
  pdfUrl?: string; // Primary direct link
  sourceUrls?: { source: string; url: string }[]; // List of multiple sources found via search
}

export interface RelatedCase {
  caseName: string;
  citation?: string;
  type: 'OVERRULED' | 'UPHELD' | 'DISTINGUISHED' | 'CITED' | 'RELIED_UPON';
  year?: number;
}

export interface TimelineEvent {
  date: string;
  event: string;
}

export interface IRAC {
  issue: string; // The legal question
  rule: string; // The relevant law/precedent
  analysis: string; // Application of law to facts
  conclusion: string; // The final holding
}

export interface CaseSummary {
  caseName: string;
  citation: string;
  court: string;
  year: number;
  benchStrength: string;
  judges: string[];
  jurisdiction: string;

  // Structured Headnote
  facts: string;
  timeline: TimelineEvent[]; 
  issues: string[];
  petitionerArguments: string;
  respondentArguments: string;

  // The Core Judgment
  decision: string; // Held
  ratioDecidendi: string; // The principle of law
  obiterDicta?: string; // Incidental remarks

  // Exam Perspective
  irac: IRAC;

  // The Street-Smart "Vakil Mode" Analysis
  vakilTake?: string; 

  significance: string; // Impact on law
  lawsInvolved: string[]; // Acts/Sections

  // Lineage
  precedents: RelatedCase[]; // Cases this case relies on
  subsequentDevelopments: RelatedCase[]; // Newer cases that cite this one

  fullTextUrl?: string; // Link to full judgment
}

export interface SearchState {
  query: string;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
  rawText?: string;
}

export interface HistoryItem {
  query: string;
  timestamp: number;
  mode: SearchMode;
  jurisdiction: Jurisdiction;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Schema definition for the structured legal output
const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation (e.g., AIR 1973 SC 1461)" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges or bench type (e.g., Constitution Bench)" },
    judges: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of judges on the bench"
    },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Extensive and detailed narrative of the material facts. For Vakil Mode, provide near-verbatim detail from the judgment where possible. Target 500+ words." },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "Date or Year" },
          event: { type: Type.STRING, description: "What happened" }
        }
      },
      description: "Chronological sequence of events."
    },
    irac: {
      type: Type.OBJECT,
      properties: {
        issue: { type: Type.STRING, description: "The specific legal question before the court." },
        rule: { type: Type.STRING, description: "The specific statutes or precedents applied (The Rule). Provide detailed citations." },
        analysis: { type: Type.STRING, description: "Comprehensive application of law to facts. This section MUST be exhaustive. Discuss majority and dissenting opinions separately if applicable. Target 800-1000 words." },
        conclusion: { type: Type.STRING, description: "The final holding." }
      },
      description: "IRAC Analysis for law students."
    },
    vakilTake: {
      type: Type.STRING,
      description: "A street-smart, practical analysis. Identify loopholes, strategic brilliance, and procedural nuances. Why was this case REALLY won or lost?"
    },
    issues: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of legal issues or questions of law raised"
    },
    petitionerArguments: { type: Type.STRING, description: "Detailed arguments by the petitioner/appellant" },
    respondentArguments: { type: Type.STRING, description: "Detailed arguments by the respondent" },
    decision: { type: Type.STRING, description: "The final verdict/holding of the court" },
    ratioDecidendi: { type: Type.STRING, description: "The core legal principle derived (Ratio)" },
    obiterDicta: { type: Type.STRING, description: "Any significant incidental remarks (Obiter)" },
    significance: { type: Type.STRING, description: "Impact on the legal landscape or future precedents" },
    lawsInvolved: {
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of Specific Acts, Articles, or Sections referenced"
    },
    precedents: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['RELIED_UPON', 'DISTINGUISHED', 'OVERRULED'] }
        }
      },
      description: "Older cases that this judgment relied upon or discussed"
    },
    subsequentDevelopments: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING, enum: ['OVERRULED', 'UPHELD', 'CITED'] },
          year: { type: Type.INTEGER }
        }
      },
      description: "List strictly the major cases that have cited, overruled, or distinguished this case in later years."
    },
    fullTextUrl: { type: Type.STRING, description: "A valid URL to the full judgment PDF or text (e.g. from indiankanoon.org or sci.gov.in) if known." }
  },
  required: ["caseName", "citation", "court", "year", "facts", "timeline", "irac", "issues", "decision", "ratioDecidendi", "significance", "subsequentDevelopments"]
};

const searchResultSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      caseName: { type: Type.STRING },
      citation: { type: Type.STRING },
      context: { type: Type.STRING, description: "Why this case matches the query" },
      pdfUrl: { type: Type.STRING, description: "Primary direct URL to PDF if available" },
      sourceUrls: { 
        type: Type.ARRAY, 
        items: {
          type: Type.OBJECT,
          properties: {
            source: { type: Type.STRING, description: "Source Name (e.g., Supreme Court, Indian Kanoon)" },
            url: { type: Type.STRING, description: "The direct link" }
          }
        },
        description: "List of multiple sources found via Google Search"
      }
    },
    required: ["caseName", "citation", "context"]
  }
};

export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    // Enhanced Prompt for Grounded Search
    const prompt = `
      You are an elite Legal Search Engine powered by Gemini.
      User Query: "${query}"
      Jurisdiction: ${jurisdiction}

      SEARCH INSTRUCTIONS:
      1. **BOOLEAN LOGIC**: Strictly interpret 'AND', 'OR', 'NOT' in the query to filter results.
      2. **ISSUE SEARCH**: If the query describes a legal issue (e.g. "triple talaq", "right to privacy"), find the leading, landmark cases on this topic.
      3. **CITATION SEARCH**: If a citation is provided, find that exact case.

      GROUNDING & PDF RETRIEVAL:
      - Use the Google Search tool to find REAL, verifyable cases.
      - **CRITICAL**: For each case, you MUST try to find direct PDF or Text URLs from reputable sources.
      - Prioritize these domains for India: main.sci.gov.in, indiankanoon.org, bombayhighcourt.nic.in, e-courts.gov.in.
      - For Global: courtlistener.com, bailii.org, canlii.org.
      - Populate the 'sourceUrls' array with as many valid links as you can find (aim for 3-4 distinct sources per case).

      Return a JSON array of the top 4 most relevant cases.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], // ENABLE GOOGLE SEARCH GROUNDING
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
        temperature: 0.1, // Lower temperature for factual accuracy
      }
    });

    // Note: In a real production environment with Grounding, we would specifically parse 
    // response.candidates[0].groundingMetadata.groundingChunks to verify the URLs.
    // Here, we rely on the model to incorporate the found URLs into the JSON schema as instructed.

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSearchResult[];
  } catch (error) {
    console.error("Search Error:", error);
    throw error;
  }
};

export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";

    const persona = isVakilMode 
      ? `You are a legendary Senior Advocate (Vakil) in the Supreme Court.
         You provide EXTREMELY DETAILED, EXHAUSTIVE, AND STRATEGIC analyses.
         Your goal is to produce a summary equivalent to a 3000-word case commentary.

         TONE: Authoritative, cynical, highly detailed, bold.

         INSTRUCTIONS FOR 'VAKIL MODE':
         1. 'facts': Must be a long narrative (at least 600 words) covering every procedural step.
         2. 'irac.analysis': Must be exhaustive (at least 1000 words). Breakdown separate opinions of judges. Quote the judgment extensively.
         3. 'subsequentDevelopments': You MUST identify cases that came after this and changed the law.`
      : `You are an expert Legal Researcher. Use formal, academic legal language. Provide a comprehensive summary (approx 1000 words).`;

    if (isRawText) {
      prompt = `
        ${persona}
        Analyze the provided raw judgment text. 
        Extract key elements into the structured format.

        Raw Text:
        """
        ${query.substring(0, 30000)} 
        """
      `;
    } else {
      prompt = `
        ${persona}
        The user wants a detailed summary of: "${query}" (${jurisdiction}).

        Provide the output in the defined JSON schema.
        Ensure 'subsequentDevelopments' is populated with array of related cases.
        Ensure 'fullTextUrl' is provided if a likely URL exists.
      `;
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], // Use search to verify facts for summary too
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
        temperature: 0.2, 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response generated");

    if (text.trim().startsWith("```")) {
      text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
    }

    return JSON.parse(text) as CaseSummary;

  } catch (error) {
    console.error("Gemini Legal Search Error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { SearchMode, Jurisdiction, HistoryItem } from '../types';

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  mode: SearchMode;
  setMode: (m: SearchMode) => void;
  jurisdiction: Jurisdiction;
  setJurisdiction: (j: Jurisdiction) => void;
  onSearch: () => void;
  isLoading: boolean;
  history: HistoryItem[];
  onHistorySelect: (item: HistoryItem) => void;
}

// Mock database for autocomplete demo
const MOCK_CASE_DB = [
  "Kesavananda Bharati v. State of Kerala",
  "Maneka Gandhi v. Union of India",
  "Minerva Mills Ltd. v. Union of India",
  "Golaknath v. State of Punjab",
  "Shah Bano Begum Case",
  "Vishaka v. State of Rajasthan",
  "Puttaswamy v. Union of India (Privacy Case)",
  "Indra Sawhney v. Union of India",
  "ADM Jabalpur v. Shivkant Shukla",
  "S.R. Bommai v. Union of India",
  "Naz Foundation v. Govt. of NCT of Delhi",
  "Navtej Singh Johar v. Union of India",
  "Shayara Bano v. Union of India (Triple Talaq)",
  "M.C. Mehta v. Union of India",
  "Common Cause v. Union of India",
  "D.K. Basu v. State of West Bengal",
  "Mohd. Ahmed Khan v. Shah Bano Begum",
  "Bachchan Singh v. State of Punjab",
  "Olga Tellis v. Bombay Municipal Corporation"
];

export const HeroSection: React.FC<HeroSectionProps> = ({
  query,
  setQuery,
  mode,
  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Autocomplete logic
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  // Click outside to close
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-32 pb-20 px-4 overflow-hidden min-h-[70vh] flex flex-col justify-center">

      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1200px] h-[800px] bg-navy-800/30 rounded-full blur-[150px] -z-10 pointer-events-none"></div>

      <div className="max-w-6xl mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-12 animate-fade-in-down flex flex-col items-center">

          <div className="relative w-28 h-28 mb-4 group cursor-default">
             <div className="absolute inset-0 bg-gold-500/10 blur-2xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
             <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl overflow-visible">
               <defs>
                 <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                   <stop offset="0%" stopColor="#b45309" />
                   <stop offset="50%" stopColor="#fbbf24" />
                   <stop offset="100%" stopColor="#b45309" />
                 </linearGradient>
               </defs>
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="url(#goldGrad)" strokeWidth="1" className="opacity-30" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fbbf24" strokeWidth="1" className="opacity-50" strokeDasharray="2 2" />
             </svg>
          </div>

          <div className="inline-flex items-center justify-center px-6 py-2 mb-6 border-y border-gold-600/30 bg-navy-950/40 backdrop-blur-md">
            <span className="text-gold-500 text-[10px] font-cinzel tracking-[0.4em] font-bold uppercase">
              Est. 2026 • AI Legal Research
            </span>
          </div>

          <h1 className="font-display text-7xl md:text-9xl font-bold mb-4 tracking-tighter text-parchment-50 drop-shadow-2xl relative inline-block">
            Juris<span className="text-shine italic font-serif font-light animate-shine">Lens</span>
          </h1>

          <div className="flex items-center justify-center gap-6 my-8 opacity-70">
            <div className="h-px w-24 bg-gradient-to-r from-transparent to-gold-600/50"></div>
            <p className="text-slate-300 text-xl font-serif italic tracking-wide">
              "Fiat Justitia Ruat Caelum"
            </p>
            <div className="h-px w-24 bg-gradient-to-l from-transparent to-gold-600/50"></div>
          </div>
        </div>

        {/* Search Interface */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-navy-950/80 backdrop-blur-2xl rounded shadow-[0_30px_100px_rgba(0,0,0,0.8)] border border-slate-700/80 p-4 max-w-5xl mx-auto transform transition-all hover:border-gold-600/40 group hover:shadow-[0_30px_100px_rgba(251,191,36,0.1)] relative z-50">
            <div className="flex flex-col md:flex-row gap-4">

              <div className="relative min-w-[200px] bg-navy-900 rounded border border-slate-800">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-5 bg-transparent text-slate-300 font-cinzel text-xs font-bold tracking-wider outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME / ISSUE</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gold-600">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                </div>
              </div>

              <div className="flex-grow relative bg-navy-900 rounded border border-slate-800 focus-within:border-gold-600/50 transition-colors">
                {mode === SearchMode.TEXT_ANALYSIS ? (
                  <textarea 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Paste full judgment text..."
                    className="w-full p-5 bg-transparent text-parchment-100 placeholder-slate-600 outline-none resize-none h-16 leading-relaxed font-serif text-base"
                  />
                ) : (
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && onSearch()}
                    placeholder="Search case name, legal issue (e.g., 'triple talaq'), or use Boolean (AND, OR, NOT)..."
                    className="w-full h-full p-5 bg-transparent text-parchment-100 placeholder-slate-600 outline-none font-serif text-xl"
                    autoComplete="off"
                  />
                )}

                {/* Autocomplete Dropdown */}
                {showSuggestions && (
                  <div className="absolute left-0 right-0 top-full mt-2 bg-navy-900 border border-slate-700 rounded shadow-xl overflow-hidden z-[100]">
                    {suggestions.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => handleSuggestionClick(s)}
                        className="w-full text-left px-5 py-3 text-slate-300 hover:bg-slate-800 hover:text-gold-400 font-serif border-b border-slate-800 last:border-0 transition-colors"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {mode !== SearchMode.TEXT_ANALYSIS && (
                 <div className="relative min-w-[160px] bg-navy-900 rounded border border-slate-800">
                 <select
                   value={jurisdiction}
                   onChange={(e) => setJurisdiction(e.target.value as Jurisdiction)}
                   className="w-full h-full p-5 bg-transparent text-slate-300 text-[10px] font-cinzel font-bold tracking-widest outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors uppercase"
                 >
                   {Object.values(Jurisdiction).map((j) => (
                     <option key={j} value={j}>{j}</option>
                   ))}
                 </select>
                 <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                 </div>
               </div>
              )}

              <button
                onClick={onSearch}
                disabled={!query.trim()}
                className="bg-gold-700 hover:bg-gold-600 disabled:bg-slate-800 disabled:text-slate-600 text-parchment-100 font-cinzel font-bold text-sm py-4 px-10 transition-all duration-300 flex items-center justify-center gap-3 min-w-[160px] shadow-[inset_0_0_20px_rgba(0,0,0,0.2)] rounded border-t border-b border-gold-500 hover:shadow-[0_0_20px_rgba(251,191,36,0.4)]"
              >
                 <span className="tracking-widest">SEARCH</span>
              </button>
            </div>

            {/* Search History Integration */}
            {history.length > 0 && (
              <div className="mt-4 flex items-center gap-2 overflow-x-auto pb-2 scrollbar-thin">
                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider shrink-0 mr-2">RECENT:</span>
