                   >
                     <span className="text-[10px] text-slate-400 font-mono group-hover:text-gold-400">{item.query}</span>
                     <span className="text-[8px] bg-black/30 px-1 rounded text-slate-500">{item.jurisdiction.slice(0,3).toUpperCase()}</span>
                   </button>
                ))}
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
};

