import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Helper function for exponential backoff
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries: number = 3,
  baseDelay: number = 2000
): Promise<T> {
  let attempt = 0;
  while (attempt < retries) {
    try {
      return await fn();
    } catch (error: any) {
      attempt++;
      // Check for 429 (Resource Exhausted) or 5xx errors
      const isRetryable = 
        error?.status === 429 || 
        error?.code === 429 || 
        error?.message?.includes('429') ||
        error?.message?.includes('quota') ||
        (error?.status >= 500 && error?.status < 600);

      if (isRetryable && attempt < retries) {
        // Exponential backoff with jitter: baseDelay * 2^attempt + random jitter
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 1000;
        console.warn(`API Error (Attempt ${attempt}/${retries}): ${error.message}. Retrying in ${Math.round(delay)}ms...`);
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw new Error("Max retries exceeded");
}

