import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

const apiKey = process.env.API_KEY;
// Backup API Key for OpenRouter (AllenAI)
// Ensure this is set in your environment variables
const openRouterApiKey = process.env.OPENROUTER_API_KEY; 

const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const modelId = "gemini-3-flash-preview"; 

// Helper function for exponential backoff (Primary API)
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries: number = 2, // Reduced retries since we have a backup now
  baseDelay: number = 1000
): Promise<T> {
  let attempt = 0;
  while (attempt < retries) {
    try {
      return await fn();
    } catch (error: any) {
      attempt++;
      const isRetryable = 
        error?.status === 429 || 
        error?.code === 429 || 
        error?.message?.includes('429') ||
        error?.message?.includes('quota') ||
        (error?.status >= 500 && error?.status < 600);

      if (isRetryable && attempt < retries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 500;
        console.warn(`Gemini API Warning (Attempt ${attempt}/${retries}): ${error.message}. Retrying...`);
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw new Error("Gemini Max retries exceeded");
}

// --- OPENROUTER / ALLEN AI BACKUP SERVICE ---

async function callOpenRouterFallback<T>(prompt: string, schema: Schema): Promise<T> {
  const key = openRouterApiKey;

  if (!key) {
    console.warn("OpenRouter API Key is missing. Cannot execute backup.");
    throw new Error("Primary API failed and Backup API Key is missing.");
  }

  console.info("⚠️ Switching to Backup Provider: AllenAI (via OpenRouter)...");

  const systemPrompt = `
    You are an expert legal AI assistant acting as a failsafe.
    The primary search engine has failed. You must provide the requested legal analysis.

    CRITICAL INSTRUCTION:
    You MUST output VALID JSON strictly adhering to the schema structure provided below.
    Do not include markdown formatting (like \`\`\`json). Output ONLY the raw JSON string.

    SCHEMA DEFINITION:
    ${JSON.stringify(schema, null, 2)}
  `;

  try {
    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${key}`,
        "Content-Type": "application/json",
        "HTTP-Referer": typeof window !== 'undefined' ? window.location.href : "https://jurislens.app",
        "X-Title": "JurisLens AI"
      },
      body: JSON.stringify({
        model: "allenai/molmo2-8b", 
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: prompt }
        ],
        temperature: 0.2,
        // response_format: { type: "json_object" } // Uncomment if model supports it strictly
      })
    });

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`OpenRouter Backup Error: ${response.status} - ${errText}`);
    }

    const data = await response.json();
    let content = data.choices?.[0]?.message?.content;

    if (!content) throw new Error("Empty response from OpenRouter backup");

    // aggressive sanitization to ensure valid JSON
    content = content.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "").trim();

    return JSON.parse(content) as T;

  } catch (error) {
    console.error("Critical Failure: Backup Provider also failed.", error);
    throw error;
  }
}

// --- SCHEMAS ---

const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges" },
    judges: { type: Type.ARRAY, items: { type: Type.STRING } },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Detailed narrative of facts." },
