const apiKey = process.env.API_KEY;
const openRouterApiKey = process.env.OPENROUTER_API_KEY; 

const ai = new GoogleGenAI({ apiKey: apiKey || "" });
const geminiModelId = "gemini-3-flash-preview"; 
const openRouterModelId = "allenai/molmo2-8b";

// --- HELPERS ---

async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries: number = 2,
  baseDelay: number = 1000,
  providerName: string = "Provider"
): Promise<T> {
  let attempt = 0;
  while (attempt < retries) {
    try {
      return await fn();
    } catch (error: any) {
      attempt++;
      const isRetryable = 
        error?.status === 429 || 
        error?.code === 429 || 
        error?.message?.includes('429') ||
        error?.message?.includes('quota') ||
        (error?.status >= 500 && error?.status < 600);

      if (isRetryable && attempt < retries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 500;
        console.warn(`${providerName} API Warning (Attempt ${attempt}/${retries}): ${error.message}. Retrying...`);
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw new Error(`${providerName} Max retries exceeded`);
}

// --- PROVIDER CALLERS ---

async function callGemini<T>(
  prompt: string, 
  schema: Schema, 
  useSearchTool: boolean = false,
  temperature: number = 0.2
): Promise<T> {
  if (!apiKey) throw new Error("Gemini API Key missing");

  const config: any = {
    responseMimeType: "application/json",
    responseSchema: schema,
    temperature: temperature,
  };

  if (useSearchTool) {
    config.tools = [{ googleSearch: {} }];
  }

  const response = await retryWithBackoff(() => ai.models.generateContent({
    model: geminiModelId,
    contents: prompt,
    config: config
  }), 2, 1000, "Gemini");

  let text = response.text;
  if (!text) throw new Error("Gemini returned empty response");

  if (text.trim().startsWith("```")) {
    text = text.replace(/^```(json)?\n?/i, "").replace(/\n?```$/, "");
  }

  return JSON.parse(text) as T;
}

async function callOpenRouter<T>(
  prompt: string, 
  schema: Schema, 
  temperature: number = 0.2
): Promise<T> {
  const key = openRouterApiKey;

  if (!key) {
    throw new Error("OpenRouter API Key is missing.");
  }

  const systemPrompt = `
    You are an expert legal AI assistant.
    Provide the requested legal analysis or search results.

    CRITICAL INSTRUCTION:
    You MUST output VALID JSON strictly adhering to the schema structure provided below.
    Do not include markdown formatting (like \`\`\`json). Output ONLY the raw JSON string.

    SCHEMA DEFINITION:
    ${JSON.stringify(schema, null, 2)}
  `;

  const response = await retryWithBackoff(async () => {
    const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${key}`,
        "Content-Type": "application/json",
        "HTTP-Referer": typeof window !== 'undefined' ? window.location.href : "https://jurislens.app",
        "X-Title": "JurisLens AI"
      },
      body: JSON.stringify({
        model: openRouterModelId, 
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: prompt }
        ],
        temperature: temperature,
      })
    });

    if (!res.ok) {
        const errText = await res.text();
        throw new Error(`Status ${res.status}: ${errText}`);
    }
    return res;
  }, 2, 1000, "OpenRouter");

  const data = await response.json();
  let content = data.choices?.[0]?.message?.content;

  if (!content) throw new Error("Empty response from OpenRouter");

  // Aggressive sanitization to ensure valid JSON
  content = content.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "").trim();

  return JSON.parse(content) as T;
}

