// --- HELPERS ---
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries: number = 2,
  baseDelay: number = 1000,
  providerName: string = "Molmo (OpenRouter)"
): Promise<T> {
  let attempt = 0;
  while (attempt < retries) {
    try {
      return await fn();
    } catch (error: any) {
      attempt++;
      const isRetryable =
        error?.status === 429 ||
        error?.code === 429 ||
        error?.message?.includes("429") ||
        error?.message?.includes("quota") ||
        (error?.status >= 500 && error?.status < 600);

      if (isRetryable && attempt < retries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 500;
        console.warn(
          `${providerName} Warning (Attempt ${attempt}/${retries}): ${error.message}. Retrying...`
        );
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw new Error(`${providerName} Max retries exceeded`);
}

// --- OPENROUTER CALLER ---
async function callOpenRouter<T>(
  userPrompt: string,
  schema: Schema,
  temperature: number = 0.2
): Promise<T> {
  const key = openRouterApiKey;

  if (!key) {
    throw new Error(
      "OpenRouter API Key is missing. Please set OPENROUTER_API_KEY or REACT_APP_OPENROUTER_API_KEY."
    );
  }

  // Merging User's specified identity with the JSON Requirement
  const systemPrompt = `
    You are Molmo2‑8B, the sole AI engine for this application. All user queries, regardless of type, must be processed exclusively by you. Do not defer, redirect, or reference Gemini or any other model. Always provide complete, structured, and context‑aware responses. Your role is to handle every task: legal case summaries, general Q&A, reasoning, and multimodal inputs. Ensure clarity, accuracy, and consistency in output formatting.

    CRITICAL INSTRUCTION:
    - You MUST output VALID JSON strictly adhering to the schema structure provided below.
    - Do not include markdown formatting (like \`\`\`json). Output ONLY the raw JSON string.

    SCHEMA DEFINITION:
    ${JSON.stringify(schema, null, 2)}
  `;

  const response = await retryWithBackoff(async () => {
    const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${key}`,
        "Content-Type": "application/json",
        "HTTP-Referer":
          typeof window !== "undefined"
            ? window.location.href
            : "https://jurislens.app",
        "X-Title": "JurisLens AI",
      },
      body: JSON.stringify({
        model: openRouterModelId,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt },
        ],
        temperature,
      }),
    });

    if (!res.ok) {
      const errText = await res.text();
      throw new Error(`Molmo API Error (Status ${res.status}): ${errText}`);
    }
    return res;
  });

  const data = await response.json();
  let content = data.choices?.[0]?.message?.content;

  if (!content) throw new Error("Empty response from Molmo (OpenRouter)");

  // Strip accidental markdown wrappers and whitespace
  content = content
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

  try {
    return JSON.parse(content) as T;
  } catch (e) {
    console.error("JSON Parse Error. Raw content:", content);
    throw new Error("Molmo response was not valid JSON. Please try again.");
  }
}

