  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  let prompt = "";

  const persona = isVakilMode
    ? `You are a legendary Senior Advocate. Provide EXHAUSTIVE, STRATEGIC, and DETAILED analysis (3000 words equivalent).
       TONE: Authoritative, cynical, sophisticated.`
    : `You are an expert Legal Researcher. Provide a comprehensive summary (1000 words).`;

  if (isRawText) {
    prompt = `
      ${persona}
      Analyze the provided raw judgment text. Extract key elements into the structured format.
      Raw Text: """ ${query.substring(0, 30000)} """
    `;
  } else {
    prompt = `
      ${persona}
      The user wants a detailed summary of: "${query}" (${jurisdiction}).

      SEARCH REQUIREMENT:
      You MUST find **9 DISTINCT LINKS** for the 'sources' array.
      Scan Official (sci.gov.in), Legal DBs (IndianKanoon), and Media (LiveLaw).

      EXTRACTION REQUIREMENT:
      - **Practical Implementation**: Explain how this is applied on the ground (Operational Protocol).
      - **Procedural History**: Step-by-step court journey.
      - **Arguments**: Separate Petitioner vs Respondent.

      ANALYTICS:
      - 'citationTrend' (Decadal), 'benchSplit', 'legalConcepts'.
    `;
  }

  // ROUTING: ALL Tasks -> Molmo2-8B (OpenRouter)
  return await callOpenRouter<CaseSummary>(prompt, caseSummarySchema, 0.2);
};

import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

// --- TYPES ---
export enum Type {
  STRING = "STRING",
  NUMBER = "NUMBER",
  INTEGER = "INTEGER",
  BOOLEAN = "BOOLEAN",
  ARRAY = "ARRAY",
  OBJECT = "OBJECT",
}

export interface Schema {
  type: Type;
  properties?: Record<string, Schema>;
  items?: Schema;
  enum?: string[];
  required?: string[];
  description?: string;
}

// --- CONFIG ---
let openRouterApiKey = "";

// 1. Try Environment Variables (Safe Check for different environments)
try {
  // @ts-ignore - Handle Vite/Modern bundlers
  if (typeof import.meta !== "undefined" && import.meta.env) {
    // @ts-ignore
    openRouterApiKey = import.meta.env.VITE_OPENROUTER_API_KEY || import.meta.env.OPENROUTER_API_KEY || "";
  }
} catch (e) {}

try {
  // @ts-ignore - Handle Node/Webpack
  if (!openRouterApiKey && typeof process !== "undefined" && process.env) {
    openRouterApiKey = process.env.OPENROUTER_API_KEY || process.env.REACT_APP_OPENROUTER_API_KEY || "";
  }
} catch (e) {}

// 2. Try Local Storage (Runtime persistence)
if (!openRouterApiKey && typeof window !== "undefined") {
  openRouterApiKey = localStorage.getItem("jurisLens_openRouterKey") || "";
}

const openRouterModelId = "allenai/molmo2-8b";

// --- API KEY MANAGEMENT ---
export const setApiKey = (key: string) => {
  openRouterApiKey = key;
  if (typeof window !== "undefined") {
    localStorage.setItem("jurisLens_openRouterKey", key);
  }
};

export const hasApiKey = () => {
  return !!openRouterApiKey && openRouterApiKey.length > 0;
};

