export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  const prompt = `
    User Query: "${query}"
    Jurisdiction: ${jurisdiction}

    SEARCH INSTRUCTIONS:
    1. **BOOLEAN LOGIC**: Strictly interpret 'AND', 'OR', 'NOT'.
    2. **ISSUE SEARCH**: Identify landmark cases for issue-based queries.

    GROUNDING & PDF RETRIEVAL (CRITICAL):
    Search specifically within these repositories for DIRECT PDF/HTML links:
    INDIA: Supreme Court (main.sci.gov.in), Indian Kanoon, eCourts.
    GLOBAL: CourtListener, BAILII, AustLII, CanLII, HUDOC.

    Return a JSON array of the top 4 most relevant cases.
  `;

  // ROUTING: ALL Tasks -> Molmo2-8B (OpenRouter)
  return await callOpenRouter<CaseSearchResult[]>(
    prompt,
    searchResultSchema,
    0.1
  );
};

