async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries: number = 2,
  baseDelay: number = 1000,
  providerName: string = "Molmo (OpenRouter)"
): Promise<T> {
  let attempt = 0;
  while (attempt < retries) {
    try {
      return await fn();
    } catch (error: any) {
      attempt++;
      const isRetryable =
        error?.status === 429 ||
        error?.code === 429 ||
        error?.message?.includes("429") ||
        error?.message?.includes("quota") ||
        (error?.status >= 500 && error?.status < 600);

      if (isRetryable && attempt < retries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 500;
        console.warn(
          `${providerName} Warning (Attempt ${attempt}/${retries}): ${error.message}. Retrying...`
        );
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw new Error(`${providerName} Max retries exceeded`);
}

// --- OPENROUTER CALLER ---
async function callOpenRouter<T>(
  userPrompt: string,
  schema: Schema,
  temperature: number = 0.2
): Promise<T> {

  const key = currentApiKey;

  if (!key) {
    throw new Error(
      "Configuration Error: API Key is missing. Please contact support or configure it in settings."
    );
  }

  const systemPrompt = `
    You are Molmo2‑8B, the exclusive legal AI engine for JurisLens.

    IDENTITY:
    - Name: JurisLens AI
    - Role: Senior Legal Analyst & Constitutional Expert
    - Jurisdiction: Focus on ${Jurisdiction.INDIA}, but capable of Global analysis.

    OPERATIONAL RULES:
    1. STRICT JSON OUTPUT: You must output ONLY valid JSON. No markdown, no commentary outside JSON.
    2. ACCURACY: Provide legally precise summaries, ratio decidendi, and citations.
    3. STRUCTURE: Follow the exact schema provided below.

    SCHEMA DEFINITION:
    ${JSON.stringify(schema, null, 2)}
  `;

  const response = await retryWithBackoff(async () => {
    const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${key}`,
        "Content-Type": "application/json",
        "HTTP-Referer": CLIENT_METADATA.url,
        "X-Title": CLIENT_METADATA.name,
      },
      body: JSON.stringify({
        model: OPENROUTER_MODEL_ID,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt },
        ],
        temperature,
        // Ensure JSON mode if supported by the model/provider
        response_format: { type: "json_object" } 
      }),
    });

    if (!res.ok) {
      const errText = await res.text();
      // Handle 401 specifically
      if (res.status === 401) {
         throw new Error("Authentication Failed: The embedded API key appears invalid. Please update it manually.");
      }
      throw new Error(`Molmo API Error (Status ${res.status}): ${errText}`);
    }
    return res;
  });

  const data = await response.json();
  let content = data.choices?.[0]?.message?.content;

  if (!content) throw new Error("Empty response from Molmo (OpenRouter)");

  // Sanitize Output
  content = content
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

  try {
    return JSON.parse(content) as T;
  } catch (e) {
    console.error("JSON Parse Error. Raw content:", content);
    throw new Error("The legal engine produced a malformed response. Please retry.");
  }
}

