export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  const prompt = `
    User Query: "${query}"
    Jurisdiction: ${jurisdiction}

    TASK: Search for legal precedents matching the query.

    INSTRUCTIONS:
    1. Identify the most relevant case laws.
    2. Provide direct PDF or source links if available in your training data.
    3. 'context' should briefly explain WHY this case is relevant to the query.

    Return a JSON array of the top 4 most relevant cases.
  `;

  return await callOpenRouter<CaseSearchResult[]>(
    prompt,
    searchResultSchema,
    0.1
  );
};

export const fetchCaseSummary = async (
  query: string,
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  let prompt = "";

  const persona = isVakilMode
    ? `MODE: VAKIL (STREET SMART). Role: Senior Advocate. Tone: Authoritative, strategic, practical.`
    : `MODE: ACADEMIC. Role: Constitutional Scholar. Tone: Formal, objective, detailed.`;

  if (isRawText) {
    prompt = `
      ${persona}
      TASK: Analyze the provided raw legal text.
      INPUT TEXT: """ ${query.substring(0, 25000)}... """
      REQUIREMENTS: Extract all schema fields. Detail IRAC.
    `;
  } else {
    prompt = `
      ${persona}
      TASK: Summarize case: "${query}" (${jurisdiction}).
      REQUIREMENTS:
      1. Sources: 9 distinct URLs.
      2. Procedural History: Lower court to final.
      3. Stats: Citation count estimate.
      OUTPUT: Full JSON matching schema.
    `;
  }

  return await callOpenRouter<CaseSummary>(prompt, caseSummarySchema, 0.2);
};

