import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

// Using Gemini 2.0 Flash for best speed/performance balance
const MODEL_ID = "gemini-2.0-flash"; 
const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey || "" });

// Schema definition for the structured legal output
const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges" },
    judges: { type: Type.ARRAY, items: { type: Type.STRING } },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Detailed narrative of material facts." },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING },
          event: { type: Type.STRING }
        }
      }
    },
    proceduralHistory: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Case journey through lower courts."
    },
    irac: {
      type: Type.OBJECT,
      properties: {
        issue: { type: Type.STRING },
        rule: { type: Type.STRING },
        analysis: { type: Type.STRING },
        conclusion: { type: Type.STRING }
      }
    },
    stats: {
      type: Type.OBJECT,
      properties: {
        citationCount: { type: Type.INTEGER },
        sentiment: {
          type: Type.OBJECT,
          properties: {
            positive: { type: Type.NUMBER },
            neutral: { type: Type.NUMBER },
            negative: { type: Type.NUMBER }
          }
        },
        impactScore: { type: Type.INTEGER },
        citationTrend: {
          type: Type.ARRAY,
          items: {
             type: Type.OBJECT,
             properties: {
               period: { type: Type.STRING },
               count: { type: Type.INTEGER }
             }
          }
        },
        benchSplit: {
          type: Type.OBJECT,
          properties: {
            majority: { type: Type.INTEGER },
            dissent: { type: Type.INTEGER }
          }
        },
        legalConcepts: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    },
    vakilTake: { type: Type.STRING },
    issues: { type: Type.ARRAY, items: { type: Type.STRING } },
    petitionerArguments: { type: Type.STRING },
    respondentArguments: { type: Type.STRING },
    decision: { type: Type.STRING },
    ratioDecidendi: { type: Type.STRING },
    obiterDicta: { type: Type.STRING },
    significance: { type: Type.STRING },
    lawsInvolved: { type: Type.ARRAY, items: { type: Type.STRING } },
    precedents: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING }
        }
      }
    },
    subsequentDevelopments: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          caseName: { type: Type.STRING },
          citation: { type: Type.STRING },
          type: { type: Type.STRING },
          year: { type: Type.INTEGER }
        }
      }
    },
    sources: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          name: { type: Type.STRING },
          url: { type: Type.STRING }
        }
      }
    }
  },
  required: ["caseName", "citation", "court", "year", "facts", "irac", "stats", "issues", "decision", "ratioDecidendi", "significance", "sources"]
};

const searchResultSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      caseName: { type: Type.STRING },
      citation: { type: Type.STRING },
      context: { type: Type.STRING },
      pdfUrl: { type: Type.STRING },
      sourceUrls: { 
        type: Type.ARRAY, 
        items: {
          type: Type.OBJECT,
          properties: {
            source: { type: Type.STRING },
            url: { type: Type.STRING }
          }
        }
      }
    },
    required: ["caseName", "citation", "context"]
  }
};

export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    const prompt = `
      User Query: "${query}" (Jurisdiction: ${jurisdiction})

      TASK: Find relevant legal precedents.
      OUTPUT: JSON Array of top 4 cases.

      For each case, try to find direct PDF/HTML links from official court websites or reputable legal databases.
    `;

    const response = await ai.models.generateContent({
      model: MODEL_ID,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
      }
    });

    const text = response.text || "[]";
    return JSON.parse(text) as CaseSearchResult[];
  } catch (error: any) {
    console.error("Search Error:", error);
    throw new Error(error.message || "Search failed. Please try again.");
  }
};

export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";

    // Optimized prompt for speed
    const persona = isVakilMode 
      ? `Role: Senior Advocate. Style: Blunt, strategic, high-impact.`
      : `Role: Legal Researcher. Style: Formal, academic, precise.`;

    if (isRawText) {
      prompt = `
        ${persona}
        Analyze the raw text provided. Extract all schema fields.
        Text: """${query.substring(0, 25000)}..."""
      `;
    } else {
      prompt = `
        ${persona}
        Summarize Case: "${query}" (${jurisdiction}).

        REQUIREMENTS:
        1. 'sources': Find exactly 5 high-quality links (Official, Legal DB, Media).
        2. 'stats': Estimate impact score and sentiment based on general legal knowledge.
        3. 'irac': Provide clear Issue, Rule, Analysis, Conclusion.
      `;
    }

    const response = await ai.models.generateContent({
      model: MODEL_ID,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], 
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No summary generated.");

    return JSON.parse(text) as CaseSummary;

  } catch (error: any) {
    console.error("Summary Error:", error);
    throw new Error(error.message || "Analysis failed. Please try a different query.");
  }
};

