                </h3>
                <p className="font-mono text-xl leading-relaxed text-white">{summary.vakilTake}</p>
              </div>
            )}

            {/* Facts Section */}
            <div className="mb-20">
              <h4 className={`${theme.fontHead} text-xl mb-8 border-b-4 ${theme.accentBorder} pb-2 inline-block ${theme.heading}`}>Facts of the Case</h4>
              <p className={`text-justify ${theme.fontBody}`}>{summary.facts}</p>
            </div>

            {/* Arguments - High Contrast Columns */}
            {(summary.petitionerArguments || summary.respondentArguments) && (
              <div className="mb-20 grid grid-cols-1 md:grid-cols-2 gap-12">
                 <div className={`p-8 border-t-8 ${theme.highlightBg} ${theme.border} border-slate-500`}>
                    <h4 className={`text-base uppercase font-black tracking-widest mb-6 ${theme.subText}`}>Petitioner</h4>
                    <p className={`text-lg leading-relaxed ${theme.textMain} font-medium`}>{summary.petitionerArguments || "N/A"}</p>
                 </div>
                 <div className={`p-8 border-t-8 ${theme.highlightBg} ${theme.border} ${isVakilMode ? 'border-highcon-yellow' : 'border-amber-600'}`}>
                    <h4 className={`text-base uppercase font-black tracking-widest mb-6 ${theme.subText}`}>Respondent</h4>
                    <p className={`text-lg leading-relaxed ${theme.textMain} font-medium`}>{summary.respondentArguments || "N/A"}</p>
                 </div>
              </div>
            )}

            {/* Ratio Decidendi - Centerpiece */}
            <div className={`mb-20 p-12 border-4 ${theme.accentBorder} rounded-xl shadow-xl ${theme.highlightBg}`}>
              <div className="text-center mb-6">
                <span className={`inline-block px-4 py-1 text-sm font-black uppercase tracking-[0.3em] ${theme.heading} border-b-2 ${theme.accentBorder}`}>Ratio Decidendi</span>
              </div>
              <p className={`text-2xl md:text-4xl font-black italic text-center leading-normal ${theme.textMain}`}>
                "{summary.ratioDecidendi}"
              </p>
            </div>

            {/* Held */}
            <div className="mb-20">
               <h4 className={`${theme.fontHead} text-xl mb-4 ${theme.heading}`}>Held / Decision:</h4>
               <p className={`${theme.fontBody} font-bold`}>{summary.decision}</p>
            </div>

            {/* IRAC Analysis */}
            {summary.irac && (
              <div className={`mb-20 border-4 ${theme.border} rounded-xl overflow-hidden`}>
                <div className={`p-6 border-b-2 ${theme.border} ${theme.highlightBg}`}>
                  <h3 className={`${theme.fontHead} text-3xl font-black ${theme.heading}`}>IRAC Analysis</h3>
                </div>
                <div className="p-10 space-y-12">
                  {[
                    { label: 'Issue', content: summary.irac.issue, icon: 'I' },
                    { label: 'Rule', content: summary.irac.rule, icon: 'R' },
                    { label: 'Analysis', content: summary.irac.analysis, icon: 'A' },
                    { label: 'Conclusion', content: summary.irac.conclusion, icon: 'C' }
                  ].map((item, i) => (
                    <div key={i} className="flex gap-6 md:gap-10">
                       <div className={`w-14 h-14 shrink-0 rounded-full flex items-center justify-center font-black text-2xl border-2 ${theme.pill}`}>
                         {item.icon}
                       </div>
                       <div>
                         <h4 className={`font-black uppercase tracking-wider text-sm mb-3 ${theme.subText}`}>{item.label}</h4>
                         <p className={`${theme.fontBody} ${theme.textMain}`}>{item.content}</p>
                       </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Timeline / Trajectory */}
            <div className={`p-10 mb-20 border-2 ${theme.border} ${theme.highlightBg}`}>
              <h3 className={`${theme.fontHead} text-2xl mb-10 text-center ${theme.heading}`}>Legal Trajectory</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                <div>
                  <h4 className={`text-sm font-black tracking-widest mb-6 border-b-2 ${theme.border} pb-2 ${theme.subText}`}>PRECEDENTS</h4>
                  <div>{summary.precedents?.length > 0 ? summary.precedents.map((p, i) => <div key={i}>{renderRelatedCase(p)}</div>) : <p className="italic opacity-50">None listed.</p>}</div>
                </div>
                <div>
                  <h4 className={`text-sm font-black tracking-widest mb-6 border-b-2 ${theme.border} pb-2 ${theme.subText}`}>SUBSEQUENT DEVELOPMENTS</h4>
                  <div>{summary.subsequentDevelopments?.length > 0 ? summary.subsequentDevelopments.map((p, i) => <div key={i}>{renderRelatedCase(p)}</div>) : <p className="italic opacity-50">None listed.</p>}</div>
                </div>
              </div>
            </div>

            {/* Sources & Stats */}
            <div className="mt-20 pt-16 border-t-4 border-dashed border-gray-600">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">

                    {/* Stats */}
                    {summary.stats && (
                      <div className={`p-8 border-2 ${theme.border} rounded-lg`}>
                         <h3 className={`${theme.fontHead} text-lg mb-6 ${theme.heading}`}>Impact Analytics</h3>
                         <div className="space-y-6">
                            <div className="flex justify-between items-center">
                              <span className="font-bold text-lg">Citations</span>
                              <span className={`text-3xl font-black ${theme.iconColor}`}>{summary.stats.citationCount}</span>
                            </div>
                            <div className="flex justify-between items-center">
                              <span className="font-bold text-lg">Impact Score</span>
                              <span className={`text-3xl font-black ${theme.iconColor}`}>{summary.stats.impactScore}/100</span>
                            </div>
                            {summary.stats.legalConcepts && (
                              <div className="flex flex-wrap gap-2 mt-4">
                                {summary.stats.legalConcepts.map((c, i) => (
                                  <span key={i} className={`px-3 py-1 text-sm font-bold border rounded-full ${theme.pill}`}>{c}</span>
                                ))}
                              </div>
                            )}
                         </div>
                      </div>
                    )}

                    {/* Links */}
                    <div className={`p-8 border-2 ${theme.border} rounded-lg`}>
                        <h3 className={`${theme.fontHead} text-lg mb-6 ${theme.heading}`}>Sources</h3>
                        <div className="flex flex-col gap-3">
                            {summary.sources && summary.sources.map((source, idx) => (
                               <a 
                                 key={idx} 
                                 href={source.url} 
                                 target="_blank" 
                                 rel="noreferrer"
                                 className={`p-4 border-2 flex items-center justify-between group transition-colors ${isVakilMode ? 'bg-zinc-900 border-zinc-700 hover:border-highcon-yellow hover:bg-black' : 'bg-white border-slate-300 hover:border-amber-600 hover:bg-amber-50'}`}
                               >
                                  <div>
                                    <div className={`text-xs font-black uppercase tracking-wider mb-1 ${theme.subText}`}>{source.type}</div>
                                    <div className={`font-bold text-lg ${theme.textMain} group-hover:underline`}>{source.name}</div>
                                  </div>
                                  <span className={`text-2xl ${theme.iconColor}`}>&rarr;</span>
                               </a>
                            ))}
                        </div>
                    </div>

                </div>
            </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { SearchMode, Jurisdiction, HistoryItem } from '../types';

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  mode: SearchMode;
  setMode: (m: SearchMode) => void;
  jurisdiction: Jurisdiction;
  setJurisdiction: (j: Jurisdiction) => void;
  onSearch: () => void;
  isLoading: boolean;
  history: HistoryItem[];
  onHistorySelect: (item: HistoryItem) => void;
}

const MOCK_CASE_DB = [
  "Kesavananda Bharati v. State of Kerala",
  "Maneka Gandhi v. Union of India",
  "Minerva Mills Ltd. v. Union of India",
  "Golaknath v. State of Punjab",
  "Vishaka v. State of Rajasthan",
  "Puttaswamy v. Union of India",
  "Indra Sawhney v. Union of India",
  "S.R. Bommai v. Union of India",
  "Navtej Singh Johar v. Union of India",
  "Shayara Bano v. Union of India"
];

export const HeroSection: React.FC<HeroSectionProps> = ({
  query,
  setQuery,
  mode,
  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-32 pb-20 px-4 overflow-hidden min-h-[70vh] flex flex-col justify-center">

      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1200px] h-[800px] bg-navy-800/30 rounded-full blur-[150px] -z-10 pointer-events-none"></div>

      <div className="max-w-7xl mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-14 animate-fade-in-down flex flex-col items-center">
          <div className="relative w-32 h-32 mb-6 group cursor-default">
             <div className="absolute inset-0 bg-gold-400/20 blur-3xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
             <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl overflow-visible">
               <defs>
                 <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                   <stop offset="0%" stopColor="#d97706" />
                   <stop offset="50%" stopColor="#fbbf24" />
                   <stop offset="100%" stopColor="#d97706" />
                 </linearGradient>
               </defs>
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="url(#goldGrad)" strokeWidth="1.5" className="opacity-50" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="url(#goldGrad)" strokeWidth="7" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="url(#goldGrad)" strokeWidth="7" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fbbf24" strokeWidth="2" className="opacity-60" strokeDasharray="3 3" />
             </svg>
          </div>

          <h1 className="font-display text-8xl md:text-9xl lg:text-[10rem] font-bold mb-6 tracking-tighter text-white drop-shadow-2xl relative inline-block">
            Juris<span className="text-shine italic font-serif font-light animate-shine text-gold-400">Lens</span>
          </h1>

          <p className="text-gray-300 text-2xl font-serif italic tracking-wide mt-4">
            AI-Powered Constitutional Research & Analysis
          </p>
        </div>

        {/* Search Interface - HIGH CONTRAST & LARGE TEXT */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-navy-950/95 backdrop-blur-2xl rounded-lg shadow-[0_30px_100px_rgba(0,0,0,0.8)] border border-slate-600 p-8 max-w-6xl mx-auto transform transition-all relative z-50">
            <div className="flex flex-col md:flex-row gap-5">

              {/* Mode Selector */}
              <div className="relative min-w-[240px] bg-black rounded border border-slate-600">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-6 bg-transparent text-white font-mono text-lg font-bold tracking-wider outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gold-400">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"></path></svg>
                </div>
              </div>

              {/* Input Field */}
              <div className="flex-grow relative bg-black rounded border border-slate-600 focus-within:border-gold-400 transition-colors">
                {mode === SearchMode.TEXT_ANALYSIS ? (
                  <textarea 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Paste full judgment text..."
                    className="w-full p-6 bg-transparent text-white placeholder-gray-500 outline-none resize-none h-24 leading-relaxed font-mono text-lg"
                  />
                ) : (
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && onSearch()}
                    placeholder="Search case name, citation, or legal issue..."
                    className="w-full h-full p-6 bg-transparent text-white placeholder-gray-500 outline-none font-sans text-2xl font-bold"
                    autoComplete="off"
                  />
                )}

                {/* Autocomplete */}
                {showSuggestions && (
                  <div className="absolute left-0 right-0 top-full mt-2 bg-navy-900 border border-slate-500 rounded shadow-2xl overflow-hidden z-[100]">
                    {suggestions.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => handleSuggestionClick(s)}
                        className="w-full text-left px-6 py-4 text-white text-lg hover:bg-slate-800 hover:text-gold-400 font-serif border-b border-slate-700 last:border-0 transition-colors"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {/* Search Button */}
              <button
                onClick={onSearch}
                disabled={!query.trim()}
                className="bg-gold-500 hover:bg-gold-400 disabled:bg-slate-800 disabled:text-slate-600 text-black font-black text-xl py-6 px-12 transition-all duration-300 flex items-center justify-center gap-3 min-w-[200px] shadow-lg rounded border-2 border-gold-600"
              >
                 <span className="tracking-widest">SEARCH</span>
              </button>
            </div>

            {/* History */}
            {history.length > 0 && (
              <div className="mt-8 flex items-center gap-4 overflow-x-auto pb-3 scrollbar-thin">
                <span className="text-sm text-gray-400 font-black uppercase tracking-wider shrink-0 mr-2">RECENT:</span>
                {history.map((item, idx) => (
                   <button 
                     key={idx}
                     onClick={() => onHistorySelect(item)}
                     className="shrink-0 flex items-center gap-2 px-5 py-3 bg-navy-900 border border-slate-600 rounded hover:border-gold-400 hover:bg-slate-800 group transition-all"
                   >
                     <span className="text-sm text-gray-200 font-mono group-hover:text-gold-400 font-bold">{item.query}</span>
                   </button>
                ))}
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
};
